const initAnimation=()=>{gsap.registerPlugin(ScrollTrigger),gsap.utils.toArray(".story-image, .story-text, .details-intro, .details-card, .map-toggle, .map-content, .timeline-item, .rsvp-note, .rsvp-box, .gift-image, .gift-text, .faq-card, .reminder-image, .reminder-content, .img-box, .gallery-social-image, .gallery-social-content, .spotify-intro, .spotify-card, .group-heading, .featured-card, .entourage-card, .sponsor-item, .party-column").forEach(o=>{gsap.fromTo(o,{opacity:0,y:60,scale:.98},{opacity:1,y:0,scale:1,duration:.95,ease:"power3.out",scrollTrigger:{trigger:o,start:"top 85%",toggleActions:"play none none reverse"}})}),gsap.utils.toArray(".section-title").forEach(o=>{gsap.from(o.children,{opacity:0,y:20,stagger:.2,duration:.8,ease:"power2.out",scrollTrigger:{trigger:o,start:"top 85%",toggleActions:"play none none reverse"}})}),gsap.timeline({scrollTrigger:{trigger:".hero",start:"top 85%",toggleActions:"play none none reverse"}}).from(".hero-subtitle",{opacity:0,y:20,duration:.8,ease:"power3.out"}).from(".hero h2",{opacity:0,y:20,duration:.8,ease:"power3.out"},"-=0.4").from(".hero h1",{opacity:0,y:40,duration:1,ease:"power3.out"}).from(".hero-weds",{opacity:0,y:20,duration:.8,ease:"power3.out"},"-=0.5").from(".hero-date",{opacity:0,y:20,duration:.8,ease:"power3.out"},"-=0.5").from(".countdown .time-box",{opacity:0,y:20,stagger:.15,duration:1.2,ease:"power3.out"},"-=0.4").from(".countdown-finished",{opacity:0,y:20,duration:.8,ease:"power3.out"},"-=1.2"),gsap.timeline({scrollTrigger:{trigger:".footer-hero",start:"top 60%",toggleActions:"play none none reverse"}}).from(".footer-signature",{opacity:0,y:40,duration:.8,ease:"power3.out"}).from(".footer-names",{opacity:0,y:30,duration:.8,ease:"power3.out"},"-=0.4").from(".footer-date",{opacity:0,y:20,duration:.8,ease:"power2.out"},"-=0.5"),gsap.utils.toArray("img").forEach(o=>{gsap.fromTo(o,{scale:1.1},{scale:1,duration:1.5,ease:"power2.out",scrollTrigger:{trigger:o,start:"top 85%",toggleActions:"play none none reverse"}})}),gsap.to(".hero-content",{y:30,ease:"none",scrollTrigger:{trigger:".hero",start:"top top",end:"bottom top",scrub:!0}})};